timeout "${ASYSTEM_HEALTHCHECK_TIMEOUT_SECONDS:-30}" bash -c 'until
/asystem/etc/checkexecuting.sh "$@" &&
PGHOST="${POSTGRES_SERVICE}" PGPORT="${POSTGRES_API_PORT}" PGPASSWORD="${POSTGRES_KEY_HASS}" PGUSER="${POSTGRES_USER_HASS}" PGDATABASE="${POSTGRES_DATABASE_HASS}" psql -qAt -c "SELECT 1" >/dev/null 2>&1 &&
PGHOST="${POSTGRES_SERVICE}" PGPORT="${POSTGRES_API_PORT}" PGPASSWORD="${POSTGRES_KEY_MLFLOW}" PGUSER="${POSTGRES_USER_MLFLOW}" PGDATABASE="${POSTGRES_DATABASE_MLFLOW}" psql -qAt -c "SELECT 1" >/dev/null 2>&1 &&
PGHOST="${POSTGRES_SERVICE}" PGPORT="${POSTGRES_API_PORT}" PGPASSWORD="${POSTGRES_KEY_WRANGLE}" PGUSER="${POSTGRES_USER_WRANGLE}" PGDATABASE="${POSTGRES_DATABASE_WRANGLE}" psql -qAt -c "SELECT 1" >/dev/null 2>&1
do
sleep "${ASYSTEM_HEALTHCHECK_INTERVAL_SECONDS:-1}";
done' _ "${POSITIONAL_ARGS[@]}" || ( echo "Health check timed out after ${ASYSTEM_HEALTHCHECK_TIMEOUT_SECONDS:-30}s" >&2; false )
